import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Check the length of user input before copying it
        if (userInput.length() > 10) {
            System.out.println("Input exceeds maximum allowed length.");
            return;
        }

        // Use StringBuilder to handle user input dynamically
        StringBuilder buffer = new StringBuilder();
        buffer.append(userInput);

        System.out.println("User input: " + buffer.toString());
    }
}

### Explanation:
취약유형: Buffer Overflow
